// ── WEEKLY REPORT — Monday PDF export (Vitals tab) ──────────────────────────
// Every Monday, a banner at the top of Vitals lets you download a one-page
// PDF health report for the week that just finished (last Mon–Sun).
//
// How it works: we compute every number from the SAME functions the rest of
// the app already uses (potatesScoreForPerson, computeTrendConfidence,
// computeMacroDonutRing, getWaterGoal, etc.) — nothing here re-derives its
// own version of a stat that already has a canonical source elsewhere, so
// the report can't drift from what Vitals/Progress show you. We then build
// a standalone HTML document, open it in a new tab, and hand it to the
// browser's native print dialog — choosing "Save as PDF" there is the
// "export to PDF" step. No PDF library, no server round-trip.
//
// Fonts are embedded directly as base64 woff2 data (see the @font-face
// block below) rather than pulled from a Google Fonts <link> — a <link>
// only works if whatever renders this into a PDF actually fetches
// external stylesheets and waits for them first, which isn't reliable
// across browsers/export paths. Embedding removes that dependency
// entirely: same fix as report-export-preview.pdf went through. Only
// Baloo 2 + JetBrains Mono are used now — Space Grotesk was dropped
// everywhere it appeared, since it was never part of the app's actual
// design system (style.css has zero uses of it either).

// ── WEEK MATH ────────────────────────────────────────────────────────────
function _reportMondayOnOrBefore(d) {
  const day = d.getDay(); // 0 Sun .. 6 Sat
  const diff = day === 0 ? -6 : 1 - day;
  const m = new Date(d);
  m.setDate(m.getDate() + diff);
  m.setHours(0, 0, 0, 0);
  return m;
}
function _reportDateSeries(startDate, n) {
  const out = [];
  for (let i = 0; i < n; i++) {
    const d = new Date(startDate);
    d.setDate(d.getDate() + i);
    out.push(toLocalDateStr(d));
  }
  return out;
}
// The most recently FULLY-FINISHED Mon–Sun week, regardless of what day
// today is — this is what makes the Settings ▸ Reports archive (below)
// testable on any day of the week, not just Monday. Correctness check:
// if today IS a Monday, "this week's Monday" is today, so this returns
// exactly last Mon–Sun (today-7 .. yesterday) — the same range the
// Monday banner has always shown. On any other day it correctly steps
// back to the last week that actually finished, instead of returning the
// in-progress current week.
function completedWeekDates() {
  const thisWeekMonday = _reportMondayOnOrBefore(new Date());
  const lastMonday = new Date(thisWeekMonday);
  lastMonday.setDate(lastMonday.getDate() - 7);
  return _reportDateSeries(lastMonday, 7);
}
function priorWeekDates(weekDates) {
  const firstDay = new Date(weekDates[0] + 'T00:00:00');
  firstDay.setDate(firstDay.getDate() - 7);
  return _reportDateSeries(firstDay, 7);
}
function isWeeklyReportDay() {
  return new Date().getDay() === 1; // Monday
}
function _reportDateRangeLabel(weekDates) {
  const fmt = ds => {
    const [y, m, d] = ds.split('-');
    const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    return `${+d} ${months[+m-1]}`;
  };
  const startY = weekDates[0].split('-')[0];
  return `${fmt(weekDates[0])} – ${fmt(weekDates[6])}, ${startY}`;
}
function _reportISOWeekNumber(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  d.setDate(d.getDate() + 4 - (d.getDay() || 7));
  const yearStart = new Date(d.getFullYear(), 0, 1);
  return Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
}

// ── PER-WEEK "already downloaded" TRACKING ──────────────────────────────
// Keyed by person + the week's Monday date, stored per-device (like the
// home-person tag) rather than synced — matches how a bank statement
// works: once you've pulled a given week's statement, that account stops
// nagging you about it, but the statement itself stays in the archive
// forever and can be re-downloaded any time.
function _reportDownloadFlagKey(person, weekKey) {
  return 'la-salud-report-dl-' + person + '-' + weekKey;
}
function isWeeklyReportDownloaded(person, weekKey) {
  try { return localStorage.getItem(_reportDownloadFlagKey(person, weekKey)) === '1'; }
  catch (e) { return false; }
}
function markWeeklyReportDownloaded(person, weekKey) {
  try { localStorage.setItem(_reportDownloadFlagKey(person, weekKey), '1'); }
  catch (e) { /* localStorage unavailable — just skip the "already grabbed" state */ }
}

// Earliest date we have ANY data for this person (entries or weigh-ins) —
// the floor for how far back the Reports archive can offer a week.
function _reportEarliestDataDate(person) {
  let min = null;
  (S.entries||[]).forEach(e => { if (e.person === person && (!min || e.date < min)) min = e.date; });
  (S.weightLog||[]).forEach(w => { if (w.person === person && (!min || w.date < min)) min = w.date; });
  return min;
}

// Every fully-completed Mon–Sun week between the earliest logged data and
// last week, most recent first — the full list Settings ▸ Reports shows.
// 520-week (~10yr) safety cap, just so a corrupted/garbage date can't spin
// this into an infinite loop; nowhere near a real usage history.
function _reportAllCompletedWeeks(person) {
  const earliest = _reportEarliestDataDate(person);
  if (!earliest) return [];
  const firstMonday = _reportMondayOnOrBefore(new Date(earliest + 'T00:00:00'));
  const lastWeek = completedWeekDates();
  const lastMonday = new Date(lastWeek[0] + 'T00:00:00');
  const weeks = [];
  const cursor = new Date(firstMonday);
  let guard = 0;
  while (cursor <= lastMonday && guard < 520) {
    weeks.push(_reportDateSeries(cursor, 7));
    cursor.setDate(cursor.getDate() + 7);
    guard++;
  }
  return weeks.reverse();
}

// ── VITALS BANNER ────────────────────────────────────────────────────────
// Rendered at the very top of #vitals-body (see renderVitals() in
// vitals.js). Only ever shown on a Monday; any other day it's simply not
// part of the render, no dismiss-state to manage.
function renderWeeklyReportBanner() {
  if (!isWeeklyReportDay()) return '';
  const weekDates = completedWeekDates();
  // Once grabbed for the week, stop nagging on Vitals — it's still sitting
  // in Settings ▸ Reports whenever it's wanted again.
  if (isWeeklyReportDownloaded(S.currentPerson, weekDates[0])) return '';
  return `<div class="day-card" style="margin-bottom:10px;display:flex;align-items:center;gap:12px;padding:14px 16px">
    <img src="https://raw.githubusercontent.com/nachostax/la-salud2/main/CALENDAR.png" alt="" style="width:40px;height:40px;object-fit:contain;flex-shrink:0">
    <div style="flex:1;min-width:0">
      <div class="box-title" style="margin-bottom:2px">Weekly Report Ready</div>
      <div class="subheader">${_reportDateRangeLabel(weekDates)}</div>
    </div>
    <button class="btn btn-sage btn-sm" onclick="downloadWeeklyReport()" style="flex-shrink:0">⬇ Download PDF</button>
  </div>`;
}

// ── SETTINGS ▸ REPORTS ARCHIVE ────────────────────────────────────────────
// Every fully-completed week, most recent first, each re-downloadable any
// time regardless of the "already downloaded" flag — that flag only
// controls whether the Vitals banner nags you, never whether the PDF
// itself is available. This is also how you can test/preview the report
// on a day that isn't Monday: just open it from here.
function renderReportsBody() {
  const el = document.getElementById('reports-body');
  if (!el) return;
  const person = S.currentPerson;
  const weeks = _reportAllCompletedWeeks(person);
  if (!weeks.length) {
    el.innerHTML = '<div style="color:var(--mist);font-size:13px;padding:24px 4px;text-align:center">No fully-completed week with logged data yet — check back after your first Monday.</div>';
    return;
  }
  el.innerHTML = weeks.map(weekDates => {
    const weekKey = weekDates[0];
    const downloaded = isWeeklyReportDownloaded(person, weekKey);
    const bd = potatesScoreForPerson(person, weekDates, weekDates);
    return `<div class="day-card" style="margin-bottom:8px;display:flex;align-items:center;gap:12px;padding:12px 14px">
      <div style="flex:1;min-width:0">
        <div style="font-size:14px;font-weight:600;color:var(--sand)">${_reportDateRangeLabel(weekDates)}</div>
        <div class="subheader" style="margin-top:2px">Score ${bd.total}/100${downloaded ? ' &middot; <span style="color:var(--sage)">downloaded</span>' : ''}</div>
      </div>
      <button class="btn btn-sage btn-sm" onclick="downloadWeeklyReport('${weekKey}')" style="flex-shrink:0">⬇ PDF</button>
    </div>`;
  }).join('');
}

// ── DATA COLLECTION ──────────────────────────────────────────────────────
// Everything below reads S.entries / S.weightLog / S.mission the exact same
// way potatesScoreForPerson / the Vitals cards / the adaptive-target engine
// already do, so a number in the PDF always matches what you'd see live in
// the app for that same week.
function buildWeeklyReportData(person, weekDates) {
  const prevDates = priorWeekDates(weekDates);

  // Canonical Potates Score for this week and last week — identical call
  // to what powers the Vitals hero card, just pinned to a fixed week
  // instead of "the last 7 days from today".
  const bd = potatesScoreForPerson(person, weekDates, weekDates);
  const prevBd = potatesScoreForPerson(person, prevDates, prevDates);

  const grouped = groupEntriesByPersonDate(S.entries);
  const dayCache = new Map();
  weekDates.concat(prevDates).forEach(d => {
    if (!dayCache.has(d)) dayCache.set(d, grouped.get(person + '|' + d) || []);
  });

  const liveMission = S.mission[person] || {};

  function mealTotalsFor(date) {
    const dm = dayCache.get(date).filter(e => e.record_type === 'meal' && !e.hypo_correction);
    const snap = dm.find(e => e.day_kcal_target > 0);
    return {
      hasData: dm.length > 0,
      kcal:    dm.reduce((a,e) => a + (e.calories||0), 0),
      protein: dm.reduce((a,e) => a + (e.protein_g||0), 0),
      carbs:   dm.reduce((a,e) => a + (e.carbs_g||0), 0),
      fat:     dm.reduce((a,e) => a + (e.fat_g||0), 0),
      kcalTarget:    (snap && snap.day_kcal_target)    || liveMission.kcal    || 0,
      proteinTarget: (snap && snap.day_protein_target) || liveMission.protein || 0,
      carbsTarget:   (snap && snap.day_carbs_target)   || liveMission.carbs   || 0,
      fatTarget:     (snap && snap.day_fat_target)     || liveMission.fat    || 0
    };
  }
  function stepsFor(date) {
    return dayCache.get(date)
      .filter(e => e.record_type === 'workout' && e.workout_type === 'Walking')
      .reduce((a,w) => a + (w.steps_logged||0), 0);
  }

  const days     = weekDates.map(d => ({ date: d, ...mealTotalsFor(d), steps: stepsFor(d) }));
  const prevDays = prevDates.map(d => ({ date: d, ...mealTotalsFor(d), steps: stepsFor(d) }));

  const logged     = days.filter(d => d.hasData);
  const prevLogged = prevDays.filter(d => d.hasData);
  const n     = logged.length || 1;
  const avg   = (key) => Math.round(logged.reduce((a,d) => a + (d[key]||0), 0) / n);
  const prevAvg = (key) => prevLogged.length ? Math.round(prevLogged.reduce((a,d) => a + (d[key]||0), 0) / prevLogged.length) : null;

  // Calories specifically come from the same canonical function Vitals/
  // Progress use (see getFoodCalorieAdherence in progress.js) rather than
  // this file's own average — this used to independently recompute the
  // same "week avg kcal vs target" and had drifted from what the app
  // itself shows (different day-inclusion rule, different divisor).
  const weekFc = getFoodCalorieAdherence(person, weekDates);
  const prevFc = getFoodCalorieAdherence(person, prevDates);
  const avgKcal          = weekFc.avg;
  const avgKcalTarget    = weekFc.avgTarget || liveMission.kcal || 0;
  const prevAvgKcalV     = prevFc.avg || null;
  const overPct = avgKcalTarget > 0 ? Math.round(((avgKcal - avgKcalTarget) / avgKcalTarget) * 100) : 0;
  const daysOnTargetCount = weekFc.dayRows.filter(d =>
    d.isComplete && d.target > 0 && Math.abs((d.total - d.target) / d.target) <= 0.10
  ).length;

  const avgProtein       = avg('protein');
  const avgCarbs         = avg('carbs');
  const avgFat           = avg('fat');
  const avgProteinTarget = avg('proteinTarget') || liveMission.protein || 0;
  const avgCarbsTarget   = avg('carbsTarget')   || liveMission.carbs   || 0;
  const avgFatTarget     = avg('fatTarget')     || liveMission.fat    || 0;

  const prevAvgProteinV = prevAvg('protein');

  // ── movement — read straight from the score breakdown so "avg steps/day"
  // here is never a different number than the Vitals Movement card shows.
  const avgSteps = bd.moveData.avgSteps;
  const prevAvgSteps = prevBd.moveData.avgSteps;

  // ── workouts, grouped by type ──
  const workoutEntries     = weekDates.flatMap(d => dayCache.get(d).filter(e => e.record_type === 'workout'));
  const prevWorkoutEntries = prevDates.flatMap(d => dayCache.get(d).filter(e => e.record_type === 'workout'));
  function groupByType(list) {
    const out = {};
    list.forEach(w => {
      const t = w.workout_type || 'Other';
      if (!out[t]) out[t] = { count: 0, totalMin: 0 };
      out[t].count++;
      out[t].totalMin += (w.duration_min||0);
    });
    return out;
  }
  const byType = groupByType(workoutEntries);
  const prevByType = groupByType(prevWorkoutEntries);
  // Always show all 4 loggable workout types (Walking/Cardio/Strength/
  // Mobility), in the same fixed order the app uses elsewhere (see
  // WORKOUT_TYPES in progress.js), rather than only the types that
  // happened to have a session this week — so a quiet week for a given
  // type is visible as "0 sessions" instead of the row disappearing.
  const workoutRows = WORKOUT_TYPES.map(t => {
    const cur = byType[t];
    const prev = prevByType[t];
    const count = cur ? cur.count : 0;
    const avgMin = cur ? Math.round(cur.totalMin / cur.count) : 0;
    const prevAvgMin = prev ? Math.round(prev.totalMin / prev.count) : null;
    return { type: t, count, avgMin, delta: (count && prevAvgMin != null) ? avgMin - prevAvgMin : null };
  });

  // ── water ──
  const wGoal = getWaterGoal(person);
  function avgWaterFor(dates) {
    let sum = 0, n2 = 0;
    dates.forEach(d => {
      if (!dayCache.get(d).some(e => e.record_type === 'meal')) return;
      n2++;
      sum += getWaterMlForEntry(getWaterEntry(person, d));
    });
    return n2 ? (sum / n2 / 1000) : 0;
  }
  const avgWaterL = avgWaterFor(weekDates);
  const prevAvgWaterL = avgWaterFor(prevDates);
  const goalWaterL = wGoal / 1000;

  // ── weight projection — ENERGY-BALANCE model, not the historical
  // weigh-in regression. The old version called computeTrendConfidence()
  // and projected forward from wherever the scale trend HAPPENED to be
  // pointing, which could show a projected loss even in a week logged
  // 50%+ over target (the trend line just hadn't caught up yet). This
  // instead answers "if this week's actual eating pattern continued for
  // 6 more weeks, what would that do to bodyweight" — i.e. this week's
  // avgKcal vs. this person's real TDEE (same BMR→TDEE chain the app's
  // own calorie-target engine uses), converted to kg via the standard
  // 7700 kcal/kg fat energy-density constant. The historical black line
  // (actual past weigh-ins) is unchanged; only the forward projection's
  // basis changes. ──
  const wLogs = (S.weightLog||[]).filter(w => w.person === person).sort((a,b) => a.date.localeCompare(b.date));
  const currentKg = wLogs.length ? wLogs[wLogs.length-1].kg : (liveMission.weight || null);
  const tdeeCalc = calculateDailyTargetFrom(liveMission, person);
  const dailyCalorieDelta = avgKcal - tdeeCalc.tdee; // +over TDEE = surplus, -under = deficit
  const weightTrendKgPerWeek = (dailyCalorieDelta * 7) / KCAL_PER_KG_FAT;
  const projected6wk = currentKg != null ? currentKg + weightTrendKgPerWeek * 6 : null;
  const histCutoff = new Date(); histCutoff.setDate(histCutoff.getDate() - 42);
  const histCutoffStr = toLocalDateStr(histCutoff);
  const weightHistory = wLogs.filter(w => w.date >= histCutoffStr);

  return {
    person, weekDates, prevDates,
    score: bd.total, prevScore: prevBd.total,
    avgKcal, avgKcalTarget, overPct, daysOnTargetCount, totalLoggedDays: logged.length,
    avgProtein, avgProteinTarget, avgCarbs, avgCarbsTarget, avgFat, avgFatTarget,
    prevAvgKcal: prevAvgKcalV, prevAvgProtein: prevAvgProteinV,
    avgSteps, prevAvgSteps,
    days,
    workoutRows, workoutSessionsTotal: workoutEntries.length, prevWorkoutSessionsTotal: prevWorkoutEntries.length,
    avgWaterL, prevAvgWaterL, goalWaterL, waterHitDays: bd.waterHitDays, waterTotalDays: bd.waterTotalDays,
    logDays: bd.logDays, loggingGaps: 7 - bd.logDays, prevLoggingGaps: 7 - prevBd.logDays,
    currentKg, projected6wk, weightTrendKgPerWeek, weightHistory, tdee: tdeeCalc.tdee
  };
}

// Same 0–100 ladder used by renderPotatesHero() in vitals.js, kept in sync
// intentionally (thresholds copied, not imported, since vitals.js's version
// is wired to the live animated bar and this one just needs a static label).
function _reportStatusLabel(score) {
  if (score >= 100) return { label: 'Legendary',       color: 'var(--sage)' };
  if (score >= 90)  return { label: 'Peak Form',       color: 'var(--sage)' };
  if (score >= 70)  return { label: 'Good Health',      color: 'var(--sage)' };
  if (score >= 50)  return { label: 'Holding Steady',  color: 'var(--ochre)' };
  if (score >= 40)  return { label: 'Needs Work',       color: 'var(--ochre)' };
  if (score >= 20)  return { label: 'Warning Zone',     color: 'var(--terra)' };
  return { label: 'Critical', color: 'var(--terra)' };
}

// ── small formatting + chart helpers ──────────────────────────────────────
function _reportDelta(val, { unit='', goodIfPositive=true, decimals=0 } = {}) {
  if (val == null || isNaN(val)) return '<span style="color:var(--mist)">—</span>';
  const rounded = decimals ? (Math.round(val*Math.pow(10,decimals))/Math.pow(10,decimals)) : Math.round(val);
  if (rounded === 0) return '<span style="color:var(--mist)">— no change</span>';
  const pos = rounded > 0;
  const good = pos === goodIfPositive;
  const arrow = pos ? '▲' : '▼';
  const cls = good ? 'pos' : 'neg';
  const shown = Math.abs(rounded) + unit;
  return `<span class="metric-delta ${cls}">${arrow} ${shown}</span>`;
}
function _reportShortDate(ds) {
  const [, m, d] = ds.split('-');
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  return `${months[+m-1]} ${+d}`;
}
// Builds the full inner SVG markup for a chart-block trend chart: gridlines,
// axis min/max scale labels, a dashed average-reference line + label,
// gradient fill under the curve, a stroke line on top, and an endpoint dot.
// Matches report.html's .trend-card chart exactly (that's the "chart's
// numbering system to understand scale" that was missing here — this was
// previously just a flat, unlabeled fill shape with no sense of scale).
function _reportTrendChartSVG(values, avgValue, width, height, colorVar, gradId) {
  const padX = 4, topPad = 11, bottomPad = 7;
  const maxV = Math.max(1, ...values.map(v => v||0));
  const minV = Math.min(...values.map(v => v||0));
  const breathing = maxV * 0.15;
  const rangeTop = maxV + breathing;
  const rangeBottom = Math.max(0, minV - breathing);
  const range = (rangeTop - rangeBottom) || 1;
  const scaleY = v => topPad + (1 - ((v||0) - rangeBottom) / range) * (height - topPad - bottomPad);
  const coords = values.map((v,i) => ({
    x: padX + (i/(values.length-1)) * (width - padX*2),
    y: scaleY(v)
  }));
  const { linePath, fillPath } = buildLineAndFill(coords, height);
  const avgY = scaleY(avgValue).toFixed(1);
  const last = coords[coords.length-1];
  const fmt = v => Math.round(v).toLocaleString();
  const avgLabelRight = last.x > width * 0.6;
  return `
      <defs>
        <linearGradient id="${gradId}" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="var(${colorVar})" stop-opacity="0.35"/>
          <stop offset="100%" stop-color="var(${colorVar})" stop-opacity="0"/>
        </linearGradient>
      </defs>
      <line x1="0" y1="${topPad+2}" x2="${width}" y2="${topPad+2}" stroke="#FFFFFF" stroke-opacity="0.12" stroke-width="1"/>
      <line x1="0" y1="${height-bottomPad-2}" x2="${width}" y2="${height-bottomPad-2}" stroke="#FFFFFF" stroke-opacity="0.12" stroke-width="1"/>
      <text x="0" y="${topPad-2}" font-family="Baloo 2" font-size="8" fill="var(--app-mist)">${fmt(rangeTop)}</text>
      <text x="0" y="${height+1}" font-family="Baloo 2" font-size="8" fill="var(--app-mist)">${fmt(rangeBottom)}</text>
      <line x1="0" y1="${avgY}" x2="${width}" y2="${avgY}" stroke="var(${colorVar})" stroke-width="1" stroke-opacity="0.6" stroke-dasharray="4,3"/>
      <text x="${avgLabelRight ? 0 : width}" y="${Math.max(9,avgY-3)}" font-family="Baloo 2" font-size="8" font-weight="700" fill="var(${colorVar})" text-anchor="${avgLabelRight?'start':'end'}">avg ${fmt(avgValue)}</text>
      <path fill="url(#${gradId})" stroke="none" d="${fillPath}"/>
      <path fill="none" stroke="var(${colorVar})" stroke-width="2" stroke-linecap="round" d="${linePath}"/>
      <circle cx="${last.x.toFixed(1)}" cy="${last.y.toFixed(1)}" r="2.8" fill="var(${colorVar})"/>`;
}
function _reportWeightChartSVG(history, currentKg, kgPerWeek, width, height) {
  const padX = 30, padY = 14, padRight = 34;
  if (!history.length || currentKg == null) {
    return `<svg viewBox="0 0 ${width} ${height}" style="width:100%;height:${height}px;display:block"></svg>`;
  }
  // Re-anchor so "today" (last logged point) sits at x=0, matching the
  // historical-window length actually available (up to 42 days back).
  const spanDays = Math.round((new Date(history[history.length-1].date+'T00:00:00') - new Date(history[0].date+'T00:00:00')) / 86400000) || 1;
  const xs = history.map(w => Math.round((new Date(w.date+'T00:00:00') - new Date(history[0].date+'T00:00:00')) / 86400000) - spanDays);
  const ys = history.map(w => w.kg);
  const slope = kgPerWeek != null ? kgPerWeek / 7 : 0;
  const projX = [0, 42];
  const centerProjY = [currentKg, currentKg + slope*42];

  // ── confidence cone — widens linearly from a point at "today" to a
  // band at +6wk. Half-width scaled off the size of the projected move
  // itself (bigger swings carry more uncertainty), with a small floor so
  // a near-flat projection still shows a visible (if narrow) cone rather
  // than collapsing to a single line. This is a visual uncertainty
  // indicator, not a statistical confidence interval — there's no
  // variance data on a single TDEE-based point estimate to derive one
  // from.
  const projectedMove = Math.abs(centerProjY[1] - currentKg);
  const bandAt42 = Math.max(0.4, projectedMove * 0.35);
  const upperY = [currentKg, centerProjY[1] + bandAt42];
  const lowerY = [currentKg, centerProjY[1] - bandAt42];

  const allX = xs.concat(projX);
  const allY = ys.concat(upperY, lowerY);
  const minX = Math.min(...allX), maxX = Math.max(...allX);
  const minY = Math.min(...allY) - 0.6, maxY = Math.max(...allY) + 0.6;
  const rangeX = (maxX - minX) || 1, rangeY = (maxY - minY) || 1;
  const tx = x => padX + ((x - minX)/rangeX) * (width - padX - padRight);
  const ty = y => padY + (1 - (y - minY)/rangeY) * (height - padY*2);

  const histPath = xs.map((x,i) => `${i===0?'M':'L'} ${tx(x).toFixed(1)},${ty(ys[i]).toFixed(1)}`).join(' ');
  const centerPath = `M ${tx(projX[0]).toFixed(1)},${ty(centerProjY[0]).toFixed(1)} L ${tx(projX[1]).toFixed(1)},${ty(centerProjY[1]).toFixed(1)}`;
  const upperPath = `${tx(projX[0]).toFixed(1)},${ty(upperY[0]).toFixed(1)} L ${tx(projX[1]).toFixed(1)},${ty(upperY[1]).toFixed(1)}`;
  const lowerPath = `${tx(projX[0]).toFixed(1)},${ty(lowerY[0]).toFixed(1)} L ${tx(projX[1]).toFixed(1)},${ty(lowerY[1]).toFixed(1)}`;
  const conePath = `M ${upperPath} L ${tx(projX[1]).toFixed(1)},${ty(lowerY[1]).toFixed(1)} L ${lowerPath.split(' L ')[0]} Z`;
  const zeroX = tx(0).toFixed(1);
  const endX = tx(42).toFixed(1);

  // ── gridlines + axis labels — 4 evenly spaced horizontal reference
  // lines spanning the chart's actual data range, each labeled with its
  // kg value on the left edge (matches the previous report's number +
  // reference-line treatment).
  const GRID_COUNT = 4;
  let gridSVG = '';
  for (let i = 0; i <= GRID_COUNT; i++) {
    const gy = minY + (rangeY * i / GRID_COUNT);
    const y = ty(gy).toFixed(1);
    gridSVG += `<line x1="${padX}" y1="${y}" x2="${width-padRight}" y2="${y}" stroke="var(--grid)" stroke-width="1"/>`;
    gridSVG += `<text x="${padX-4}" y="${(+y+3).toFixed(1)}" font-size="8" fill="var(--mist)" text-anchor="end">${gy.toFixed(1)}</text>`;
  }

  return `<svg viewBox="0 0 ${width} ${height}" style="width:100%;height:${height}px;display:block">
    ${gridSVG}
    <line x1="${zeroX}" y1="${padY}" x2="${zeroX}" y2="${height-padY}" stroke="var(--grid)" stroke-width="1"/>
    <path d="${conePath}" fill="var(--ochre)" fill-opacity="0.14" stroke="none"/>
    <path d="M ${upperPath}" fill="none" stroke="var(--ochre)" stroke-width="1" stroke-opacity="0.5"/>
    <path d="M ${lowerPath}" fill="none" stroke="var(--ochre)" stroke-width="1" stroke-opacity="0.5"/>
    <path d="${histPath}" fill="none" stroke="var(--soil)" stroke-width="1.8"/>
    <path d="${centerPath}" fill="none" stroke="var(--ochre)" stroke-width="1.8" stroke-dasharray="5,3"/>
    <circle cx="${zeroX}" cy="${ty(currentKg).toFixed(1)}" r="2.6" fill="var(--soil)"/>
    <circle cx="${endX}" cy="${ty(centerProjY[1]).toFixed(1)}" r="2.6" fill="var(--ochre)"/>
    <text x="${zeroX}" y="${padY-3}" font-size="8" fill="var(--mist)" text-anchor="middle">today</text>
    <text x="${endX}" y="${ty(upperY[1])-3}" font-size="7.5" fill="var(--mist)" text-anchor="end">${upperY[1].toFixed(1)}</text>
    <text x="${endX}" y="${(+ty(lowerY[1])+9).toFixed(1)}" font-size="7.5" fill="var(--mist)" text-anchor="end">${lowerY[1].toFixed(1)}</text>
    <text x="${endX}" y="${(ty(centerProjY[1])-8).toFixed(1)}" font-size="8.5" font-weight="700" fill="var(--ochre)" text-anchor="end">${centerProjY[1].toFixed(1)} kg</text>
  </svg>`;
}

// Reads the CURRENTLY ACTIVE theme's identity colors straight off the page
// (so a Gabi report picks up her blue "moon" accent instead of Nacho's
// ochre) while keeping the report's own page background/text tones fixed —
// this is a printable light-background document, not a copy of the app's
// dark in-app theme, the same way report-export-preview.pdf was designed.
function _reportThemeColors() {
  const cs = getComputedStyle(document.body);
  const pick = (name, fallback) => (cs.getPropertyValue(name)||'').trim() || fallback;
  return {
    ochre: pick('--ochre', '#C8863A'),
    sage:  pick('--sage',  '#7A9E7E'),
    terra: pick('--terra', '#C4614A'),
    // computeMacroDonutRing() (ui.js) falls back to var(--clay) for the
    // ring's unfilled segment. This document's :root never defined --clay,
    // so that conic-gradient() color-stop was invalid and the WHOLE
    // gradient dropped to nothing — leaving only the separate terra
    // overage arc visible. Reading the live value here (same pattern as
    // ochre/sage/terra above) fixes that regardless of which person's
    // theme (earth brown vs moon navy) is active.
    clay:  pick('--clay',  '#38322A'),
    fat:   '#8B6BC0', // fixed macro-identity color app-wide, see MACRO_FAT_COLOR in ui.js
    // Dark chart-card tokens (Steps/Calories charts) — these were previously
    // hardcoded to Nacho's ochre-toned dark palette regardless of who the
    // report was for. Reading them live the same way as ochre/sage/terra
    // above makes the chart card and its text follow Gabi's blue "moon"
    // theme when her report is generated.
    bark:     pick('--bark',      '#252118'),
    mist:     pick('--mist',      '#9A9080'),
    bone:     pick('--bone',      '#F2EBE0'),
    boxTitle: pick('--box-title', '#D9C093')
  };
}

// ── HTML DOCUMENT ──────────────────────────────────────────────────────────
function buildWeeklyReportHTML(data) {
  const theme = _reportThemeColors();
  const status = _reportStatusLabel(data.score);
  const scoreDelta = data.score - data.prevScore;
  const personLabel = data.person === 'gabi' ? 'GABI' : 'NACHO';

  const donut = computeMacroDonutRing(data.avgKcal, data.avgProtein, data.avgCarbs, data.avgFat, data.avgKcalTarget, '#EDE4D3');
  const overageArc = data.overPct > 0 ? Math.min(data.overPct, 60) : 0; // clamp the ring's overage sliver so a huge overshoot doesn't visually eat the whole donut

  const stepsChartSVG = _reportTrendChartSVG(data.days.map(d => d.steps), data.avgSteps, 520, 128, '--sage', 'gradSteps');
  const kcalChartSVG  = _reportTrendChartSVG(data.days.map(d => d.kcal), data.avgKcal, 520, 128, '--ochre', 'gradCal');
  const chartDateLabels = `<div class="chart-labels"><span>${_reportShortDate(data.weekDates[0])}</span><span>${_reportShortDate(data.weekDates[6])}</span></div>`;
  const weightSVG = _reportWeightChartSVG(data.weightHistory, data.currentKg, data.weightTrendKgPerWeek, 620, 110);

  const metricRow = (name, desc, deltaHtml) => `
      <div class="metric-row">
        <div><span class="metric-name">${name}</span><span class="metric-desc">${desc}</span></div>
        <div>${deltaHtml}</div>
      </div>`;

  const metricsHtml =
    metricRow('Calories', `${data.daysOnTargetCount}/${data.totalLoggedDays||7} days on target`,
      _reportDelta(data.prevAvgKcal!=null ? -(Math.abs(data.avgKcal-data.avgKcalTarget) - Math.abs(data.prevAvgKcal-data.avgKcalTarget)) : null, {unit:'kcal/day closer to target'})) +
    metricRow('Protein', `avg ${data.avgProtein}g / ${data.avgProteinTarget||'—'}g target`,
      _reportDelta(data.prevAvgProtein!=null ? data.avgProtein-data.prevAvgProtein : null, {unit:'g/day'})) +
    metricRow('Steps', `avg ${data.avgSteps.toLocaleString()} / day`,
      _reportDelta(data.avgSteps-data.prevAvgSteps, {unit:'/day'})) +
    metricRow('Workouts', `${data.workoutSessionsTotal} sessions logged`,
      _reportDelta(data.workoutSessionsTotal-data.prevWorkoutSessionsTotal, {unit:' sessions'})) +
    metricRow('Water', `avg ${data.avgWaterL.toFixed(1)}L / ${data.goalWaterL.toFixed(1)}L target`,
      _reportDelta(data.avgWaterL-data.prevAvgWaterL, {unit:'L/day', decimals:1})) +
    metricRow('Logging gaps', `${data.loggingGaps} day${data.loggingGaps!==1?'s':''} missing`,
      _reportDelta(data.prevLoggingGaps-data.loggingGaps, {unit:' fewer gap(s)'}));

  const workoutRowsHtml = data.workoutRows.map(w => `
      <div class="workout-row${w.count===0 ? ' workout-row-empty' : ''}">
        <div class="workout-dot"></div>
        <div class="workout-name">${w.count} ${w.type} session${w.count!==1?'s':''}</div>
        <div class="workout-dur">${w.count ? w.avgMin+'min avg' : '—'}</div>
        <div class="workout-delta">${w.delta==null ? '' : (w.delta>0?'▲ +':w.delta<0?'▼ ':'')+(w.delta===0?'no change':Math.abs(w.delta)+'min')}</div>
      </div>`).join('');

  return `<!doctype html>
<html>
<head>
<meta charset="utf-8">
<title>La Salud — Weekly Report — ${personLabel} — ${data.weekDates[0]}</title>
<style>
  @font-face {
    font-family: 'Baloo 2';
    font-style: normal;
    font-weight: 400;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }
  @font-face {
    font-family: 'Baloo 2';
    font-style: normal;
    font-weight: 500;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }
  @font-face {
    font-family: 'Baloo 2';
    font-style: normal;
    font-weight: 600;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }
  @font-face {
    font-family: 'Baloo 2';
    font-style: normal;
    font-weight: 700;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }
  @font-face {
    font-family: 'JetBrains Mono';
    font-style: normal;
    font-weight: 400;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }
  @font-face {
    font-family: 'JetBrains Mono';
    font-style: normal;
    font-weight: 500;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }
  @font-face {
    font-family: 'JetBrains Mono';
    font-style: normal;
    font-weight: 600;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }
  @font-face {
    font-family: 'JetBrains Mono';
    font-style: normal;
    font-weight: 700;
    font-display: block;
    src: url(data:font/woff2;base64,) format('woff2');
  }

  :root{
    --soil:#181510; --ochre:${theme.ochre}; --sage:${theme.sage}; --terra:${theme.terra}; --fat:${theme.fat}; --clay:${theme.clay};
    --mist:#8A8375; --grid:#E7E0D4; --sand:#F2E5D4; --cream:#FBF6E8; --bone:#FBF8F2;
    /* Dark chart-card tokens — same as report.html's trend-card, used
       only by .chart-block (Steps/Calories charts), never by the rest
       of the (light) page. */
    --app-bark:${theme.bark}; --app-mist:${theme.mist}; --app-bone:${theme.bone}; --app-boxtitle:${theme.boxTitle};
  }
  *{
    box-sizing:border-box;
    /* Without this, print/PDF export drops background colors and
       gradients by default — this is what was silently eating the
       .chart-block dark background (and would've eaten the donut ring
       too) on export even after the CSS rule below is added. */
    -webkit-print-color-adjust:exact; print-color-adjust:exact; color-adjust:exact;
  }
  html,body{ margin:0; padding:0; background:#F4EFE4; }
  /* A4, not US Letter — narrower (210mm vs 8.5in) and taller (297mm vs 11in). */
  @page{ size:210mm 297mm; margin:0; }
  @media print{ .no-print{ display:none !important; } html,body{ background:#FFFFFF; } }
  body{ font-family:'Baloo 2', system-ui, sans-serif; color:var(--soil); -webkit-font-smoothing:antialiased; }
  .page{ width:210mm; min-height:297mm; margin:0 auto; background:#FFFFFF; padding:30px 40px 36px; position:relative; }
  .toolbar{ max-width:210mm; margin:0 auto 14px; display:flex; gap:10px; justify-content:flex-end; padding-top:14px; }
  .toolbar button{ font-family:'Baloo 2',sans-serif; font-size:13px; font-weight:600; letter-spacing:0.5px; padding:9px 16px; border-radius:10px; border:none; cursor:pointer; }
  .toolbar .print-btn{ background:var(--ochre); color:#fff; }
  .toolbar .close-btn{ background:#E2DACB; color:var(--soil); }

  .eyebrow{ font-family:'JetBrains Mono',monospace; font-size:10.5px; font-weight:500; letter-spacing:1.6px; text-transform:uppercase; color:var(--mist); }
  .eyebrow.accent{ color:var(--ochre); }
  .header{ display:flex; justify-content:space-between; align-items:flex-start; }
  h1.title{
    /* Matches the app's .pf-title as actually rendered, not as declared:
       the app's own Google Fonts import only has Baloo 2 400/600, so
       .pf-title's CSS font-weight:700 has no true-Bold face to use and
       silently falls back to 600 (SemiBold) on screen. Using 600 here
       to match what "Vitals"/"Kitchen" actually look like. */
    font-family:'Baloo 2',sans-serif; font-weight:600; font-size:34px; letter-spacing:0.2px; margin:2px 0 4px;
  }
  .date-range{ font-size:14px; color:var(--mist); font-weight:500; }
  .name-pill{ display:inline-block; font-family:'JetBrains Mono',monospace; font-size:11px; font-weight:600; letter-spacing:1.2px; color:var(--ochre); background:var(--sand); padding:5px 12px; border-radius:20px; }
  .badge{ width:96px; height:96px; flex-shrink:0; }
  .rule{ height:2px; background:var(--soil); margin:16px 0 22px; border:none; }

  .section-label{ margin-bottom:8px; }
  .score-row{ display:flex; gap:26px; align-items:stretch; }
  .score-card{ width:220px; flex-shrink:0; background:var(--cream); border-radius:18px; padding:18px 20px 18px; }
  .score-status{ font-family:'JetBrains Mono',monospace; font-size:12px; font-weight:600; letter-spacing:2px; text-transform:uppercase; }
  .score-num{ font-family:'Baloo 2',sans-serif; font-weight:700; font-size:52px; line-height:1; margin:10px 0 14px; }
  .score-num span{ font-size:20px; font-weight:500; color:var(--mist); }
  .score-bar-track{ height:6px; border-radius:4px; background:var(--grid); overflow:hidden; }
  .score-bar-fill{ height:100%; border-radius:4px; }
  .score-delta{ margin-top:8px; font-size:12px; font-weight:600; }
  .score-lastweek{ margin-top:2px; font-size:12px; color:var(--mist); }

  .metric-list{ flex:1; display:flex; flex-direction:column; justify-content:space-between; }
  .metric-row{ display:flex; justify-content:space-between; align-items:baseline; padding:5px 0; border-bottom:1px solid var(--grid); gap:12px; }
  .metric-row:last-child{ border-bottom:none; }
  .metric-name{ font-size:14.5px; font-weight:600; }
  .metric-desc{ font-size:12px; color:var(--mist); margin-left:8px; font-weight:400; }
  .metric-delta{ font-size:13px; font-weight:700; white-space:nowrap; }
  .metric-delta.pos{ color:var(--sage); }
  .metric-delta.neg{ color:var(--terra); }

  /* Two-column grid instead of two independently-sized flex rows: donut
     card / workout card share column 1, Calories / Steps charts share
     column 2 — so both charts end up the exact same width, and the
     workout card ends up the exact same width as the donut card, no
     matter what either column's content happens to measure. */
  .stats-grid{ display:grid; grid-template-columns:320px 1fr; column-gap:34px; row-gap:24px; margin-top:26px; align-items:stretch; }
  .donut-col{ display:flex; gap:20px; align-items:center; }
  .donut-wrap{ position:relative; width:160px; height:160px; flex-shrink:0; }
  /* App's own .donut/.donut-hole ring is 14px thick on a 104px circle —
     a 13.5% thickness-to-diameter ratio. The macro ring here sits on a
     128px circle, so it needs an ~17px band (128 * 0.135 ≈ 17) to read
     as the same weight, not the old 14px flat copy that looked thin at
     this larger size. */
  .donut-hole{ position:absolute; top:32px; left:32px; width:96px; height:96px; border-radius:50%; background:#FFFFFF; display:flex; flex-direction:column; align-items:center; justify-content:center; }
  .donut-hole-kcal{ font-family:'Baloo 2',sans-serif; font-weight:700; font-size:21px; line-height:1; }
  .donut-hole-lbl{ font-family:'JetBrains Mono',monospace; font-size:9.5px; letter-spacing:1.2px; text-transform:uppercase; color:var(--mist); margin-top:4px; }
  .legend{ display:flex; flex-direction:column; gap:9px; }
  .legend-item{ display:flex; align-items:center; gap:9px; }
  .legend-dot{ width:10px; height:10px; border-radius:3px; flex-shrink:0; }
  .legend-txt{ font-size:13.5px; font-weight:600; width:56px; }
  .legend-val{ font-size:13px; color:var(--mist); font-weight:500; }

  /* This class was used in the HTML markup below but had no matching CSS
     rule anywhere in this file — that's the actual bug behind the Steps/
     Calories charts rendering with no background at all. Matches
     report.html's .trend-card treatment exactly. */
  .chart-block{
    background:var(--app-bark); border-radius:14px; padding:12px 16px;
    /* Fixed, not 100%: the two chart-blocks sit in different grid rows
       (one next to the donut card, one next to the workout card), so
       stretching each to 100% of its own row let them end up different
       heights whenever those two rows differed. A shared fixed height
       guarantees Calories and Steps always match. */
    height:184px; box-sizing:border-box;
    display:flex; flex-direction:column; justify-content:center;
  }
  .chart-head{ display:flex; justify-content:space-between; align-items:baseline; }
  .chart-title{
    font-family:'Baloo 2',sans-serif; font-size:12px; font-weight:600;
    letter-spacing:1.2px; color:var(--app-boxtitle); text-transform:uppercase;
  }
  .chart-avg{ font-family:'Baloo 2',sans-serif; font-size:11px; color:var(--app-mist); }
  .chart-avg b{ color:var(--app-bone); font-weight:700; }
  .chart-svg{ width:100%; height:128px; display:block; margin-top:6px; }
  .chart-labels{
    display:flex; justify-content:space-between; margin-top:1px;
    font-family:'Baloo 2',sans-serif; font-size:8.5px; color:var(--app-mist);
  }

  .workout-card{ background:var(--cream); border-radius:18px; padding:16px 18px 16px; display:flex; flex-direction:column; justify-content:center; }
  .workout-row{ display:flex; align-items:baseline; gap:5px; padding:7px 0; border-bottom:1px solid var(--grid); }
  .workout-row:last-child{ border-bottom:none; }
  .workout-dot{ width:6px; height:6px; border-radius:50%; background:var(--ochre); flex-shrink:0; }
  .workout-name{ font-size:14px; font-weight:600; flex:1; }
  .workout-dur{ font-size:12.5px; color:var(--mist); width:auto; white-space:nowrap; text-align:right; }
  .workout-delta{ font-size:12.5px; font-weight:700; color:var(--terra); width:70px; text-align:right; }
  /* Zero-session rows (a type simply wasn't logged this week) read as
     quiet/neutral, not as a missing-data warning. */
  .workout-row-empty .workout-name{ color:var(--mist); font-weight:500; }
  .workout-row-empty .workout-dot{ background:var(--grid); }

  .weight-section{ margin-top:22px; }
  .weight-card{ background:var(--cream); border-radius:18px; padding:16px 18px 16px; margin-top:10px; }
  .weight-head{ display:flex; justify-content:space-between; }
  .weight-stat-lbl{ font-family:'JetBrains Mono',monospace; font-size:9.5px; letter-spacing:1.2px; text-transform:uppercase; color:var(--mist); }
  .weight-stat-val{ font-size:20px; font-weight:700; margin-top:3px; }
  .weight-stat-val.accent{ color:var(--ochre); }

  @media print{
    .score-card, .metric-list, .donut-col, .chart-block, .workout-card, .weight-card, .header{
      break-inside: avoid;
      page-break-inside: avoid;
    }
  }
</style>
</head>
<body>

<div class="toolbar no-print">
  <button class="print-btn" onclick="window.print()">🖨 Print / Save as PDF</button>
  <button class="close-btn" onclick="window.close()">Close</button>
</div>

<div class="page">

  <div class="header">
    <div>
      <div class="eyebrow accent">LA SALUD</div>
      <h1 class="title">Health Report</h1>
      <div style="display:flex; align-items:center; gap:10px;">
        <div class="date-range">${_reportDateRangeLabel(data.weekDates)}</div>
        <div class="name-pill">${personLabel}</div>
      </div>
    </div>
<!-- Real STAMP.png (nachostax/la-salud2), inlined as base64 — same
         reason as everything else here: zero external requests needed
         to render, so it shows up the same in the tab and in the PDF
         export regardless of network access. -->
    <img class="badge" src="data:image/png;base64," alt="Official Potato Report">
  </div>

  <hr class="rule">

  <div class="eyebrow section-label">WEEKLY SCORE</div>
  <div class="score-row">
    <div class="score-card">
      <div class="score-status" style="color:${status.color}">${status.label.toUpperCase()}</div>
      <div class="score-num">${data.score}<span>/100</span></div>
      <div class="score-bar-track"><div class="score-bar-fill" style="width:${Math.max(0,Math.min(100,data.score))}%;background:${status.color}"></div></div>
      <div class="score-delta" style="color:${scoreDelta>=0?'var(--sage)':'var(--terra)'}">${scoreDelta>=0?'▲ +':'▼ '}${Math.abs(scoreDelta)} vs last week</div>
      <div class="score-lastweek">Last week: ${data.prevScore}/100</div>
    </div>
    <div class="metric-list">${metricsHtml}</div>
  </div>

  <div class="stats-grid">
    <div class="donut-col">
      <div class="donut-wrap">
        ${overageArc > 0 ? `<div style="position:absolute;top:0;left:0;width:160px;height:160px;border-radius:50%;background:conic-gradient(var(--terra) 0% ${overageArc}%, transparent ${overageArc}% 100%)"></div>` : ''}
        <div style="position:absolute;top:12px;left:12px;width:136px;height:136px;border-radius:50%;background:#FFFFFF"></div>
        <div style="position:absolute;top:16px;left:16px;width:128px;height:128px;border-radius:50%;background:${donut.background}"></div>
        <div class="donut-hole">
          <div class="donut-hole-kcal">${data.avgKcal.toLocaleString()}</div>
          <div class="donut-hole-lbl">kcal</div>
        </div>
      </div>
      <div class="legend">
        <div class="legend-item"><div class="legend-dot" style="background:var(--sage)"></div><div class="legend-txt">Protein</div><div class="legend-val">${data.avgProtein} / ${data.avgProteinTarget}g</div></div>
        <div class="legend-item"><div class="legend-dot" style="background:var(--ochre)"></div><div class="legend-txt">Carbs</div><div class="legend-val">${data.avgCarbs} / ${data.avgCarbsTarget}g</div></div>
        <div class="legend-item"><div class="legend-dot" style="background:var(--fat)"></div><div class="legend-txt">Fat</div><div class="legend-val">${data.avgFat} / ${data.avgFatTarget}g</div></div>
      </div>
    </div>
    <div class="chart-block">
      <div class="chart-head">
        <div class="chart-title">Calories</div>
        <div class="chart-avg">avg <b>${data.avgKcal.toLocaleString()}</b> kcal &nbsp; ${_reportDelta(data.prevAvgKcal!=null?data.avgKcal-data.prevAvgKcal:null,{unit:'kcal/day',goodIfPositive:false})}</div>
      </div>
      <svg class="chart-svg" viewBox="0 0 520 128" preserveAspectRatio="none">${kcalChartSVG}</svg>
      ${chartDateLabels}
    </div>

    <div class="workout-card">${workoutRowsHtml}</div>
    <div class="chart-block">
      <div class="chart-head">
        <div class="chart-title">Steps</div>
        <div class="chart-avg">avg <b>${data.avgSteps.toLocaleString()}</b> / day &nbsp; ${_reportDelta(data.avgSteps-data.prevAvgSteps,{unit:'/day'})}</div>
      </div>
      <svg class="chart-svg" viewBox="0 0 520 128" preserveAspectRatio="none">${stepsChartSVG}</svg>
      ${chartDateLabels}
    </div>
  </div>

  <div class="weight-section">
    <div class="eyebrow section-label">WEIGHT PROJECTION</div>
    <div class="weight-card">
      <div class="weight-head">
        <div><div class="weight-stat-lbl">TODAY</div><div class="weight-stat-val">${data.currentKg!=null ? data.currentKg.toFixed(1)+' kg' : '—'}</div></div>
        <div><div class="weight-stat-lbl">PROJECTED IN 6 WEEKS</div><div class="weight-stat-val accent">${data.projected6wk!=null ? data.projected6wk.toFixed(1)+' kg' : 'no weight on record yet'}</div></div>
      </div>
      ${weightSVG}
    </div>
  </div>

</div>
</body>
</html>`;
}

// ── ENTRY POINT (Vitals banner button AND Settings > Reports rows) ───────
// With no argument, downloads the most recently completed week (the
// Monday banner's use). Pass a Monday date string ('YYYY-MM-DD') to
// download any other completed week from the Settings > Reports archive.
function downloadWeeklyReport(weekKey) {
  // Open the tab FIRST, synchronously, inside the click handler — some
  // browsers block window.open() once anything async has happened in
  // between, even something as small as building the report data.
  const win = window.open('', '_blank');
  if (!win) { showToast('Please allow pop-ups to download the report'); return; }

  const person = S.currentPerson;
  const weekDates = weekKey ? _reportDateSeries(new Date(weekKey + 'T00:00:00'), 7) : completedWeekDates();
  const data = buildWeeklyReportData(person, weekDates);
  const html = buildWeeklyReportHTML(data);

  win.document.open();
  win.document.write(html);
  win.document.close();

  // Auto-open the print dialog once the tab has laid out; the on-page
  // "Print / Save as PDF" button (hidden in the print output itself) is
  // there as a manual fallback for browsers that block a scripted print()
  // in a freshly-opened tab.
  win.addEventListener('load', () => {
    setTimeout(() => { try { win.focus(); win.print(); } catch(e) {} }, 300);
  });

  markWeeklyReportDownloaded(person, weekDates[0]);
  // If the Vitals banner for THIS week is currently on screen, drop it
  // immediately rather than waiting for the next natural re-render.
  if (typeof renderVitals === 'function' && document.getElementById('vitals-body')) renderVitals();
  // If the Reports archive list is open, refresh its "downloaded" tag too.
  if (document.getElementById('reports-body')) renderReportsBody();
}
